patch:
diff --git a/drivers/pcmcia/cs.c b/drivers/pcmcia/cs.c
index 7c93a10..262313e 100644
--- a/drivers/pcmcia/cs.c
+++ b/drivers/pcmcia/cs.c
@@ -53,7 +53,6 @@ MODULE_LICENSE("GPL");

 INT_MODULE_PARM(setup_delay,	10);		/* centiseconds */
 INT_MODULE_PARM(resume_delay,	20);		/* centiseconds */
-INT_MODULE_PARM(shutdown_delay,	3);		/* centiseconds */
 INT_MODULE_PARM(vcc_settle,	40);		/* centiseconds */
 INT_MODULE_PARM(reset_time,	10);		/* usecs */
 INT_MODULE_PARM(unreset_delay,	10);		/* centiseconds */
@@ -393,8 +392,6 @@ static void socket_shutdown(struct pcmcia_socket *s)
 	cs_dbg(s, 4, "shutdown\n");

 	socket_remove_drivers(s);
-	s->state &= SOCKET_INUSE | SOCKET_PRESENT;
-	msleep(shutdown_delay * 10);
 	s->state &= SOCKET_INUSE;

 	/* Blank out the socket state */
@@ -409,6 +406,9 @@ static void socket_shutdown(struct pcmcia_socket *s)
 #endif
 	s->functions = 0;

+	/* give socket some time to power down */
+	msleep(100);
+
 	s->ops->get_status(s, &status);
 	if (status & SS_POWERON) {
 		printk(KERN_ERR "PCMCIA: socket %p: *** DANGER *** unable to remove socket power\n", s);
